1	// POST /api/admin/brain/synthesize
2	//
3	// Admin-only endpoint to manually trigger brain synthesis for a given section.
4	// Dispatches the Trigger.dev 'brain-synthesis' task and returns immediately.
5	// The actual synthesis runs asynchronously.
6	//
7	// Request body: { sectionId: string, trigger?: 'admin' | 'new_claims' }
8	
9	import { NextResponse, type NextRequest } from 'next/server';
10	import { z } from 'zod';
11	import { requireAdmin } from '@/lib/auth-guard';
12	import { triggerTask } from '@/lib/trigger';
13	import { getDirectDb } from '@oracle/db/client';
14	import { eq } from 'drizzle-orm';
15	import { brainSections } from '@oracle/db/schema';
16	
17	export const dynamic = 'force-dynamic';
18	
19	const BodySchema = z.object({
20	  sectionId: z.string().min(1),
21	  trigger: z.enum(['admin', 'new_claims']).optional().default('admin'),
22	});
23	
24	export async function POST(req: NextRequest) {
25	  try {
26	    await requireAdmin();
27	  } catch {
28	    return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
29	  }
30	
31	  let body: z.infer<typeof BodySchema>;
32	  try {
33	    body = BodySchema.parse(await req.json());
34	  } catch (err) {
35	    return NextResponse.json({ error: 'bad_request', detail: String(err) }, { status: 400 });
36	  }
37	
38	  // Verify the section exists.
39	  const db = getDirectDb();
40	  const [section] = await db
41	    .select({ id: brainSections.id, title: brainSections.title })
42	    .from(brainSections)
43	    .where(eq(brainSections.id, body.sectionId))
44	    .limit(1);
45	
46	  if (!section) {
47	    return NextResponse.json(
48	      { error: 'not_found', detail: `Brain section "${body.sectionId}" does not exist.` },
49	      { status: 404 },
50	    );
51	  }
52	
53	  await triggerTask('brain-synthesis', {
54	    sectionId: body.sectionId,
55	    trigger: body.trigger,
56	  });
57	
58	  return NextResponse.json({
59	    ok: true,
60	    sectionId: body.sectionId,
61	    title: section.title,
62	    triggered: true,
63	    note: 'Synthesis task dispatched. Check admin/brain for results.',
64	  });
65	}
