1	// POST /api/admin/documents — admin company-document upload (no channel).
2	//
3	// Unlike POST /api/documents (which attaches a file to a chat channel), this
4	// endpoint uploads knowledge documents directly: it stores the bytes, inserts a
5	// `documents` row, and triggers `document-ingestion`. The ingestion worker reads
6	// the document by id and does not need a channel, so company/process documents
7	// can be uploaded from Admin → Documents without starting a chat.
8	//
9	// Accepts multipart/form-data with one or more `files` (and/or a single `file`).
10	// Requires admin.
11	
12	import { NextResponse, type NextRequest } from 'next/server';
13	import { eq } from 'drizzle-orm';
14	import { requireAdmin } from '@/lib/auth-guard';
15	import { getDirectDb } from '@oracle/db/client';
16	import { createServiceRoleClient } from '@oracle/auth/server';
17	import { documents } from '@oracle/db/schema';
18	import { triggerTask } from '@/lib/trigger';
19	
20	export const dynamic = 'force-dynamic';
21	// Allow time for several files to upload in one request.
22	export const maxDuration = 60;
23	
24	const BUCKET = 'company_documents';
25	
26	type UploadResult =
27	  | { fileName: string; ok: true; documentId: string }
28	  | { fileName: string; ok: false; error: string };
29	
30	export async function POST(req: NextRequest) {
31	  // 1. Auth — admin only.
32	  let me;
33	  try {
34	    me = await requireAdmin();
35	  } catch {
36	    return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
37	  }
38	
39	  // 2. Parse multipart body.
40	  let formData: FormData;
41	  try {
42	    formData = await req.formData();
43	  } catch {
44	    return NextResponse.json({ error: 'Expected multipart/form-data' }, { status: 400 });
45	  }
46	
47	  const files: File[] = [
48	    ...formData.getAll('files').filter((f): f is File => f instanceof File),
49	  ];
50	  const single = formData.get('file');
51	  if (single instanceof File) files.push(single);
52	
53	  if (files.length === 0) {
54	    return NextResponse.json({ error: 'No files provided' }, { status: 400 });
55	  }
56	
57	  // Optional uploader context applied to every file in this upload.
58	  const contextRaw = formData.get('context');
59	  const context = typeof contextRaw === 'string' && contextRaw.trim() ? contextRaw.trim() : null;
60	
61	  let domainHints: string[] | null = null;
62	  const hintsRaw = formData.get('domainHints');
63	  if (typeof hintsRaw === 'string' && hintsRaw.trim()) {
64	    try {
65	      const parsed = JSON.parse(hintsRaw);
66	      if (Array.isArray(parsed)) {
67	        const ids = parsed.filter((x): x is string => typeof x === 'string' && x.length > 0);
68	        if (ids.length > 0) domainHints = ids;
69	      }
70	    } catch {
71	      // Ignore malformed hints — they're an optional prior, not load-bearing.
72	    }
73	  }
74	
75	  const db = getDirectDb();
76	  const serviceSupabase = createServiceRoleClient();
77	  const results: UploadResult[] = [];
78	
79	  for (const file of files) {
80	    const safeName = file.name.replace(/[^a-zA-Z0-9._-]/g, '_');
81	    const storagePath = `admin/${me.id}/${Date.now()}-${safeName}`;
82	
83	    // Upload bytes via service-role client (bypasses storage RLS).
84	    const bytes = await file.arrayBuffer();
85	    const { error: uploadError } = await serviceSupabase.storage
86	      .from(BUCKET)
87	      .upload(storagePath, bytes, {
88	        contentType: file.type || 'application/octet-stream',
89	        upsert: false,
90	      });
91	    if (uploadError) {
92	      results.push({ fileName: file.name, ok: false, error: uploadError.message });
93	      continue;
94	    }
95	
96	    // Insert the documents row.
97	    let docId: string;
98	    try {
99	      const [doc] = await db
100	        .insert(documents)
101	        .values({
102	          uploaderId: me.id,
103	          fileName: file.name,
104	          storageBucket: BUCKET,
105	          storagePath,
106	          fileType: file.type || 'application/octet-stream',
107	          status: 'pending_processing',
108	          context,
109	          domainHints,
110	        })
111	        .returning({ id: documents.id });
112	      if (!doc) throw new Error('Insert returned no row');
113	      docId = doc.id;
114	    } catch (err) {
115	      // Roll back the orphaned storage object.
116	      await serviceSupabase.storage.from(BUCKET).remove([storagePath]);
117	      console.error('[admin/documents] insert failed', err);
118	      results.push({ fileName: file.name, ok: false, error: 'DB insert failed' });
119	      continue;
120	    }
121	
122	    // Kick off ingestion before returning. Serverless functions may stop
123	    // fire-and-forget work as soon as the response is sent.
124	    const dispatched = await triggerTask('document-ingestion', { documentId: docId });
125	    if (!dispatched) {
126	      await db
127	        .update(documents)
128	        .set({
129	          processingError:
130	            'Immediate ingestion dispatch failed. The scheduled sweep will retry this document automatically.',
131	        })
132	        .where(eq(documents.id, docId));
133	    }
134	    results.push({ fileName: file.name, ok: true, documentId: docId });
135	  }
136	
137	  const anyOk = results.some((r) => r.ok);
138	  return NextResponse.json({ ok: anyOk, results }, { status: anyOk ? 201 : 502 });
139	}
