1	import { randomUUID } from 'node:crypto';
2	import { NextResponse, type NextRequest } from 'next/server';
3	import { eq } from 'drizzle-orm';
4	import { z } from 'zod';
5	import { requireAdmin } from '@/lib/auth-guard';
6	import { getDirectDb } from '@oracle/db/client';
7	import { channelParticipants, channels, messages } from '@oracle/db/schema';
8	
9	export const dynamic = 'force-dynamic';
10	
11	const MAX_IMPORT_CHARS = 100_000;
12	const MAX_MESSAGE_CHARS = 9_000;
13	type OracleDb = ReturnType<typeof getDirectDb>;
14	
15	const BodySchema = z.object({
16	  title: z.string().trim().min(1).max(120),
17	  sourceLabel: z.string().trim().max(200).optional(),
18	  content: z.string().trim().min(20).max(MAX_IMPORT_CHARS),
19	  channelId: z.uuid().optional(),
20	});
21	
22	function splitIntoMessageSizedChunks(content: string): string[] {
23	  const normalized = content.replace(/\r\n/g, '\n').trim();
24	  if (normalized.length <= MAX_MESSAGE_CHARS) return [normalized];
25	
26	  const chunks: string[] = [];
27	  let current = '';
28	  const paragraphs = normalized.split(/\n{2,}/);
29	
30	  for (const paragraph of paragraphs) {
31	    const candidate = current ? `${current}\n\n${paragraph}` : paragraph;
32	    if (candidate.length <= MAX_MESSAGE_CHARS) {
33	      current = candidate;
34	      continue;
35	    }
36	
37	    if (current) {
38	      chunks.push(current);
39	      current = '';
40	    }
41	
42	    if (paragraph.length <= MAX_MESSAGE_CHARS) {
43	      current = paragraph;
44	      continue;
45	    }
46	
47	    for (let start = 0; start < paragraph.length; start += MAX_MESSAGE_CHARS) {
48	      chunks.push(paragraph.slice(start, start + MAX_MESSAGE_CHARS));
49	    }
50	  }
51	
52	  if (current) chunks.push(current);
53	  return chunks;
54	}
55	
56	async function resolveImportChannel(db: OracleDb, args: {
57	  channelId?: string;
58	  title: string;
59	  employeeId: string;
60	}) {
61	  if (args.channelId) {
62	    const [channel] = await db
63	      .select({ id: channels.id, status: channels.status, isGroupChat: channels.isGroupChat })
64	      .from(channels)
65	      .where(eq(channels.id, args.channelId))
66	      .limit(1);
67	
68	    if (!channel || channel.status !== 'active' || !channel.isGroupChat) {
69	      throw new Error('Target channel must be an active group channel.');
70	    }
71	
72	    await db
73	      .insert(channelParticipants)
74	      .values({ channelId: channel.id, employeeId: args.employeeId })
75	      .onConflictDoNothing();
76	    return channel.id;
77	  }
78	
79	  const safeTitle = args.title.replace(/\s+/g, ' ').trim();
80	  const [channel] = await db
81	    .insert(channels)
82	    .values({
83	      name: `Import: ${safeTitle}`,
84	      isGroupChat: true,
85	      status: 'active',
86	    })
87	    .returning({ id: channels.id });
88	
89	  if (!channel) throw new Error('Failed to create import channel.');
90	
91	  await db
92	    .insert(channelParticipants)
93	    .values({ channelId: channel.id, employeeId: args.employeeId })
94	    .onConflictDoNothing();
95	
96	  return channel.id;
97	}
98	
99	export async function POST(request: NextRequest) {
100	  let me;
101	  try {
102	    me = await requireAdmin();
103	  } catch {
104	    return NextResponse.json({ error: 'Unauthenticated' }, { status: 401 });
105	  }
106	
107	  let body: z.infer<typeof BodySchema>;
108	  try {
109	    body = BodySchema.parse(await request.json());
110	  } catch (err) {
111	    return NextResponse.json(
112	      { error: 'Invalid request body', detail: err instanceof Error ? err.message : 'validation failed' },
113	      { status: 400 },
114	    );
115	  }
116	
117	  const db = getDirectDb();
118	  const importId = randomUUID();
119	  const chunks = splitIntoMessageSizedChunks(body.content);
120	
121	  try {
122	    const result = await db.transaction(async (tx) => {
123	      const channelId = await resolveImportChannel(tx as ReturnType<typeof getDirectDb>, {
124	        channelId: body.channelId,
125	        title: body.title,
126	        employeeId: me.id,
127	      });
128	
129	      const now = new Date().toISOString();
130	      const inserted = await tx
131	        .insert(messages)
132	        .values(
133	          chunks.map((chunk, index) => ({
134	            channelId,
135	            employeeId: me.id,
136	            role: 'user' as const,
137	            content: chunk,
138	            clientMessageId: `admin-import:${importId}:${index + 1}`,
139	            extractionStatus: 'pending' as const,
140	            metadataJson: {
141	              importId,
142	              importSource: 'admin_raw_import',
143	              title: body.title,
144	              sourceLabel: body.sourceLabel ?? null,
145	              part: index + 1,
146	              totalParts: chunks.length,
147	              importedByEmployeeId: me.id,
148	              importedAt: now,
149	            },
150	          })),
151	        )
152	        .returning({ id: messages.id });
153	
154	      return { channelId, messageIds: inserted.map((row) => row.id) };
155	    });
156	
157	    return NextResponse.json(
158	      {
159	        importId,
160	        channelId: result.channelId,
161	        messageIds: result.messageIds,
162	        messageCount: result.messageIds.length,
163	        status: 'pending_extraction',
164	      },
165	      { status: 201 },
166	    );
167	  } catch (err) {
168	    const message = err instanceof Error ? err.message : 'Import failed';
169	    const status = message.includes('Target channel') ? 400 : 500;
170	    return NextResponse.json({ error: message }, { status });
171	  }
172	}
