1	// GET  /api/admin/model-catalog   — read persisted catalog (with pricing/caps)
2	// POST /api/admin/model-catalog   — refresh from provider APIs + OpenRouter, upsert into DB
3	//
4	// Model list comes from the 3 direct provider APIs (Anthropic, OpenAI, Google Gemini).
5	// Pricing and capability flags are enriched from openrouter.ai/api/v1/models.
6	// The catalog lives in the model_capabilities Postgres table; this endpoint does
7	// not call any external API on GET — that only happens on POST (admin
8	// "Refresh catalog" button or a future cron).
9	
10	import { NextResponse } from 'next/server';
11	import { getCurrentEmployee } from '@/lib/auth-guard';
12	import { getDirectDb } from '@oracle/db/client';
13	import {
14	  loadModelCatalog,
15	  refreshModelCatalog,
16	  getCatalogRefreshedAt,
17	  type ModelCapability,
18	} from '@oracle/ai';
19	
20	export const dynamic = 'force-dynamic';
21	
22	export type ModelCatalogEntry = {
23	  id: string;
24	  name: string;
25	  provider: 'anthropic' | 'openai' | 'google' | 'deepseek' | 'qwen';
26	  contextLength: number | null;
27	  maxOutputTokens: number | null;
28	  promptPer1M: number | null;
29	  completionPer1M: number | null;
30	  vision: boolean;
31	  pdf: boolean;
32	  thinking: boolean;
33	  tools: boolean;
34	  structuredOutputs: boolean;
35	  promptCaching: boolean;
36	  outputCap: boolean;
37	  knowledgeCutoff: string | null;
38	};
39	
40	function capabilityToEntry(cap: ModelCapability): ModelCatalogEntry {
41	  return {
42	    id: cap.id,
43	    name: cap.displayName,
44	    provider: cap.provider,
45	    contextLength: cap.contextLength,
46	    maxOutputTokens: cap.maxOutputTokens,
47	    promptPer1M: cap.promptPer1mUsd,
48	    completionPer1M: cap.completionPer1mUsd,
49	    vision: cap.vision,
50	    pdf: cap.pdf,
51	    thinking: cap.thinking,
52	    tools: cap.toolCalling,
53	    structuredOutputs: cap.structuredOutputs,
54	    promptCaching: cap.promptCaching,
55	    outputCap: cap.outputCap,
56	    knowledgeCutoff: cap.knowledgeCutoff,
57	  };
58	}
59	
60	/**
61	 * Drop models that have NO pricing AND NO capability flags.
62	 *
63	 * `refreshModelCatalog` (D13 quality filters) drops these at write time, but
64	 * old rows from before the filter shipped — or rows written when OpenRouter
65	 * enrichment was unavailable — can still be in the DB. Apply the same filter
66	 * at read time so the admin UI never has to render them. Models priced at
67	 * >= $15.01/1M are also dropped here for the same reason.
68	 */
69	function passesQualityFilter(cap: ModelCapability): boolean {
70	  const hasPrice = cap.promptPer1mUsd != null;
71	  const hasCaps =
72	    cap.vision || cap.pdf || cap.thinking ||
73	    cap.structuredOutputs || cap.toolCalling ||
74	    cap.promptCaching || cap.outputCap;
75	  if (!hasPrice && !hasCaps) return false;
76	  if (cap.promptPer1mUsd != null && cap.promptPer1mUsd >= 15.01) return false;
77	  return true;
78	}
79	
80	export async function GET() {
81	  const employee = await getCurrentEmployee();
82	  if (!employee?.isAdmin) {
83	    return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
84	  }
85	
86	  const db = getDirectDb();
87	  const [catalog, refreshedAt] = await Promise.all([
88	    loadModelCatalog(db),
89	    getCatalogRefreshedAt(db),
90	  ]);
91	
92	  const filtered = catalog.filter(passesQualityFilter);
93	  return NextResponse.json({
94	    models: filtered.map(capabilityToEntry),
95	    refreshedAt: refreshedAt ? refreshedAt.toISOString() : null,
96	    catalogSize: filtered.length,
97	  });
98	}
99	
100	export async function POST() {
101	  const employee = await getCurrentEmployee();
102	  if (!employee?.isAdmin) {
103	    return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
104	  }
105	
106	  const db = getDirectDb();
107	  try {
108	    const { catalog, written, refreshedAt, errors, unenrichedIds } = await refreshModelCatalog(db);
109	    // The refresh function applies the quality filter at write time, but a
110	    // belt-and-suspenders pass here keeps the read shape consistent.
111	    const filtered = catalog.filter(passesQualityFilter);
112	    return NextResponse.json({
113	      models: filtered.map(capabilityToEntry),
114	      written,
115	      refreshedAt,
116	      errors,         // non-fatal per-source errors (e.g. one provider API was down)
117	      unenrichedIds,  // model IDs with no OpenRouter match — shown in admin diagnostics
118	    });
119	  } catch (err) {
120	    return NextResponse.json(
121	      { error: 'refresh_failed', detail: err instanceof Error ? err.message : String(err) },
122	      { status: 502 },
123	    );
124	  }
125	}
