1	// GET /api/admin/models?stage=interview|extraction|synthesis|<auxiliary id>
2	//
3	// Returns the model list for the ModelPicker on /admin/settings. Reads the
4	// persisted model_capabilities table for capability + pricing data — no
5	// provider API calls per request.
6	//
7	// Strategy:
8	//   1. Pipeline stages (interview/extraction/synthesis) read the per-stage
9	//      model_pool_${stage} setting: non-empty pool → only those rows; empty →
10	//      full catalog (the client filters by the stage's required caps).
11	//   2. Any auxiliary-model id (general-purpose, vision, …) draws from the full
12	//      catalog; the client filters by that aux model's single required
13	//      capability (or not at all).
14	//
15	// Requires admin.
16	
17	import { NextResponse, type NextRequest } from 'next/server';
18	import { eq } from 'drizzle-orm';
19	import { requireAdmin } from '@/lib/auth-guard';
20	import { getDirectDb } from '@oracle/db/client';
21	import { settings } from '@oracle/db/schema';
22	import {
23	  MODEL_POOL_SETTING_KEYS,
24	  AUXILIARY_MODEL_IDS,
25	  loadModelCatalog,
26	  type ModelCapability,
27	} from '@oracle/ai';
28	
29	export const dynamic = 'force-dynamic';
30	
31	export type ModelInfo = {
32	  id: string;
33	  name: string;
34	  provider: string;
35	  contextLength: number | null;
36	  promptPer1M: number | null;
37	  completionPer1M: number | null;
38	  // Canonical capability fields (matches model_capabilities DB columns and
39	  // the shared stage-requirements module in apps/web/lib/stage-requirements.ts).
40	  vision: boolean;
41	  thinking: boolean;
42	  tools: boolean;
43	  structuredOutputs: boolean;
44	  promptCaching: boolean;
45	  outputCap: boolean;
46	  pdf: boolean;
47	  // Legacy aliases kept for older client code (channel chat, document upload)
48	  // that still uses the friendly names. Remove after those callers migrate.
49	  files: boolean;       // alias for pdf
50	  reasoning: boolean;   // alias for thinking
51	  imageGen: boolean;    // not currently sourced; always false
52	};
53	
54	function capabilityToModelInfo(cap: ModelCapability): ModelInfo {
55	  return {
56	    id: cap.id,
57	    name: cap.displayName,
58	    provider: cap.provider,
59	    contextLength: cap.contextLength,
60	    promptPer1M: cap.promptPer1mUsd,
61	    completionPer1M: cap.completionPer1mUsd,
62	    vision: cap.vision,
63	    thinking: cap.thinking,
64	    tools: cap.toolCalling,
65	    structuredOutputs: cap.structuredOutputs,
66	    promptCaching: cap.promptCaching,
67	    outputCap: cap.outputCap,
68	    pdf: cap.pdf,
69	    files: cap.pdf,
70	    reasoning: cap.thinking,
71	    imageGen: false,
72	  };
73	}
74	
75	type PipelineStage = 'interview' | 'extraction' | 'synthesis';
76	type ModelScope = { kind: 'stage'; stage: PipelineStage } | { kind: 'full' };
77	
78	function parseScope(req: NextRequest): ModelScope {
79	  const raw = req.nextUrl.searchParams.get('stage');
80	  if (raw === 'interview' || raw === 'extraction' || raw === 'synthesis') {
81	    return { kind: 'stage', stage: raw };
82	  }
83	  // Any auxiliary-model id (general-purpose, vision, …) → full catalog; the
84	  // client filters by that model's required capability.
85	  if (raw && AUXILIARY_MODEL_IDS.has(raw)) {
86	    return { kind: 'full' };
87	  }
88	  return { kind: 'stage', stage: 'interview' };
89	}
90	
91	export async function GET(req: NextRequest) {
92	  try {
93	    await requireAdmin();
94	  } catch {
95	    return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
96	  }
97	
98	  const scope = parseScope(req);
99	  const db = getDirectDb();
100	  const catalog = await loadModelCatalog(db);
101	
102	  // Auxiliary-model pickers draw from the full catalog (no per-stage pool); the
103	  // client filters by the aux model's single required capability.
104	  if (scope.kind === 'full') {
105	    return NextResponse.json({ models: catalog.map(capabilityToModelInfo) });
106	  }
107	
108	  const poolKey = MODEL_POOL_SETTING_KEYS[scope.stage];
109	  const poolRow = await db
110	    .select({ value: settings.value })
111	    .from(settings)
112	    .where(eq(settings.key, poolKey))
113	    .limit(1);
114	
115	  const pool: string[] = Array.isArray(poolRow[0]?.value) ? (poolRow[0]!.value as string[]) : [];
116	
117	  if (pool.length > 0) {
118	    const poolSet = new Set(pool);
119	    return NextResponse.json({
120	      models: catalog.filter((c) => poolSet.has(c.id)).map(capabilityToModelInfo),
121	    });
122	  }
123	
124	  return NextResponse.json({ models: catalog.map(capabilityToModelInfo) });
125	}
126

1	// GET  /api/admin/settings          — read all settings rows
2	// POST /api/admin/settings          — upsert a single setting by key
3	//
4	// Both endpoints require admin.
5	
6	import { NextResponse, type NextRequest } from 'next/server';
7	import { eq } from 'drizzle-orm';
8	import { z } from 'zod';
9	import { requireAdmin } from '@/lib/auth-guard';
10	import { getDirectDb } from '@oracle/db/client';
11	import { settings } from '@oracle/db/schema';
12	
13	export const dynamic = 'force-dynamic';
