1	// POST /api/documents — server-side document upload.
2	//
3	// Handles the full upload flow on the server so that:
4	//   * The Storage PUT uses the service-role client (bypasses storage RLS).
5	//   * The documents / messages / message_attachments inserts use getDirectDb()
6	//     (service role, bypasses table RLS).
7	//   * The caller's session is validated server-side via requireEmployee().
8	//
9	// Accepts multipart/form-data with fields:
10	//   file      — the binary file (required)
11	//   channelId — UUID of the target channel (required)
12	
13	import { NextResponse, type NextRequest } from 'next/server';
14	import { and, eq } from 'drizzle-orm';
15	import { requireEmployee } from '@/lib/auth-guard';
16	import { getDirectDb } from '@oracle/db/client';
17	import { createServiceRoleClient } from '@oracle/auth/server';
18	import {
19	  channels,
20	  channelParticipants,
21	  documents,
22	  messages,
23	  messageAttachments,
24	} from '@oracle/db/schema';
25	import { triggerTask } from '@/lib/trigger';
26	
27	export const dynamic = 'force-dynamic';
28	
29	// Allow up to 50 MB per upload (Next.js default is 4 MB).
30	export const maxDuration = 60; // seconds
31	
32	const BUCKET = 'company_documents';
33	
34	export async function POST(req: NextRequest) {
35	  // 1. Auth.
36	  let me;
37	  try {
38	    me = await requireEmployee();
39	  } catch {
40	    return NextResponse.json({ error: 'Unauthenticated' }, { status: 401 });
41	  }
42	
43	  // 2. Parse multipart body.
44	  let formData: FormData;
45	  try {
46	    formData = await req.formData();
47	  } catch {
48	    return NextResponse.json({ error: 'Expected multipart/form-data' }, { status: 400 });
49	  }
50	
51	  const fileEntry = formData.get('file');
52	  const channelId = formData.get('channelId');
53	  const captionRaw = formData.get('caption');
54	  const caption = typeof captionRaw === 'string' ? captionRaw.trim() : '';
55	
56	  if (!(fileEntry instanceof File)) {
57	    return NextResponse.json({ error: 'Missing file field' }, { status: 400 });
58	  }
59	  if (typeof channelId !== 'string' || !channelId.trim()) {
60	    return NextResponse.json({ error: 'Missing channelId field' }, { status: 400 });
61	  }
62	
63	  const db = getDirectDb();
64	
65	  // 3. Confirm channel membership.
66	  const membership = await db
67	    .select()
68	    .from(channelParticipants)
69	    .where(
70	      and(
71	        eq(channelParticipants.channelId, channelId),
72	        eq(channelParticipants.employeeId, me.id),
73	      ),
74	    )
75	    .limit(1);
76	
77	  if (membership.length === 0) {
78	    return NextResponse.json({ error: 'Not a channel participant' }, { status: 403 });
79	  }
80	
81	  // 4. Confirm channel is active.
82	  const channelRows = await db
83	    .select({ status: channels.status })
84	    .from(channels)
85	    .where(eq(channels.id, channelId))
86	    .limit(1);
87	
88	  if (!channelRows[0] || channelRows[0].status !== 'active') {
89	    return NextResponse.json({ error: 'Channel not found or not active' }, { status: 404 });
90	  }
91	
92	  // 5. Upload bytes to Supabase Storage via service-role client (bypasses RLS).
93	  const safeName = fileEntry.name.replace(/[^a-zA-Z0-9._-]/g, '_');
94	  const storagePath = `${me.id}/${channelId}/${Date.now()}-${safeName}`;
95	
96	  const bytes = await fileEntry.arrayBuffer();
97	  const serviceSupabase = createServiceRoleClient();
98	
99	  const { error: uploadError } = await serviceSupabase.storage
100	    .from(BUCKET)
101	    .upload(storagePath, bytes, {
102	      contentType: fileEntry.type || 'application/octet-stream',
103	      upsert: false,
104	    });
105	
106	  if (uploadError) {
107	    console.error('[documents] storage upload failed', uploadError);
108	    return NextResponse.json(
109	      { error: 'Storage upload failed', detail: uploadError.message },
110	      { status: 502 },
111	    );
112	  }
113	
114	  // 6. Insert documents row.
115	  let docId: string;
116	  try {
117	    const [doc] = await db
118	      .insert(documents)
119	      .values({
120	        uploaderId: me.id,
121	        fileName: fileEntry.name,
122	        storageBucket: BUCKET,
123	        storagePath,
124	        fileType: fileEntry.type || 'application/octet-stream',
125	        status: 'pending_processing',
126	      })
127	      .returning({ id: documents.id });
128	
129	    if (!doc) throw new Error('Insert returned no row');
130	    docId = doc.id;
131	  } catch (err) {
132	    // Roll back the storage object so we don't leave orphaned files.
133	    await serviceSupabase.storage.from(BUCKET).remove([storagePath]);
134	    console.error('[documents] documents insert failed', err);
135	    return NextResponse.json({ error: 'DB insert failed' }, { status: 500 });
136	  }
137	
138	  // 7. Insert an "Attached: <filename>" message + the attachment join row.
139	  //    This makes the upload visible in the channel timeline.
140	  let attachmentMessage: {
141	    id: string;
142	    channelId: string;
143	    employeeId: string | null;
144	    role: string;
145	    content: string;
146	    createdAt: Date;
147	  } | null = null;
148	
149	  try {
150	    const [msg] = await db
151	      .insert(messages)
152	      .values({
153	        channelId,
154	        employeeId: me.id,
155	        role: 'user',
156	        content: caption || `Attached: ${fileEntry.name}`,
157	        extractionStatus: 'skipped',
158	      })
159	      .returning({
160	        id: messages.id,
161	        channelId: messages.channelId,
162	        employeeId: messages.employeeId,
163	        role: messages.role,
164	        content: messages.content,
165	        createdAt: messages.createdAt,
166	      });
167	
168	    if (msg) {
169	      attachmentMessage = msg;
170	      await db.insert(messageAttachments).values({
171	        messageId: msg.id,
172	        documentId: docId,
173	      });
174	    }
175	  } catch (err) {
176	    // Non-fatal: the document is stored; the attachment message is cosmetic.
177	    console.error('[documents] message/attachment insert failed', err);
178	  }
179	
180	  // Kick off ingestion before returning. Serverless functions may stop
181	  // fire-and-forget work as soon as the response is sent.
182	  const dispatched = await triggerTask('document-ingestion', { documentId: docId });
183	  if (!dispatched) {
184	    await db
185	      .update(documents)
186	      .set({
187	        processingError:
188	          'Immediate ingestion dispatch failed. The scheduled sweep will retry this document automatically.',
189	      })
190	      .where(eq(documents.id, docId));
191	  }
192	
193	  return NextResponse.json(
194	    {
195	      ok: true,
196	      documentId: docId,
197	      storagePath,
198	      message: attachmentMessage
199	        ? {
200	            id: attachmentMessage.id,
201	            channelId: attachmentMessage.channelId,
202	            employeeId: attachmentMessage.employeeId,
203	            role: attachmentMessage.role,
204	            content: attachmentMessage.content,
205	            createdAt: attachmentMessage.createdAt,
206	            authorName: me.name,
207	          }
208	        : null,
209	    },
210	    { status: 201 },
211	  );
212	}
