1	// R8 — Oracle chat route (refactored through OracleAIClient).
2	//
3	// Per docs/oracle/05-ai-retrofit-phase-packet.md Phase R8.
4	//
5	// What changed vs the legacy route:
6	//   - The model call goes through OracleAIClient.runText via the direct
7	//     provider adapters (Vertex / Anthropic / OpenAI raw SDKs —
8	//     DECISIONS.md D6 / D9) using the curated interview route from
9	//     `settings.default_interview_route` (R1 setting key) — not via
10	//     `getOpenRouter()` directly.
11	//   - oracle_context_packs + model_run_usage_details rows are written
12	//     for every chat turn so cache-hit / fallback dashboards work.
13	//   - The chat route executes retrieval deterministically before the model call
14	//     (recent messages, open gaps, approved claims); multi-turn message history
15	//     and temperature are passed through providerOptions.
16	//
17	// What stays the same:
18	//   - Auth + channel-participation check.
19	//   - Direct-mention gate for group chats (spec Part 10 group chat rules).
20	//   - Retrieval bundle: recent messages, employee profile, top open gaps,
21	//     top relevant approved claims. No full Brain stuffing.
22	//   - Vision-capable model detection + selective attachment downloads.
23	//   - Assistant message inserted via service-role client.
24	
25	import { NextResponse, type NextRequest } from 'next/server';
26	import { eq, and, inArray } from 'drizzle-orm';
27	import { desc } from 'drizzle-orm';
28	import { createHash } from 'node:crypto';
29	import { writeFile, unlink } from 'node:fs/promises';
30	import { tmpdir } from 'node:os';
31	import { join } from 'node:path';
32	import { z } from 'zod';
33	import { coerceLocale } from '@oracle/shared';
34	import { createServiceRoleClient } from '@oracle/auth/server';
35	import {
36	  ORACLE_SYSTEM_PROMPT,
37	  ORACLE_SYSTEM_PROMPT_VERSION,
38	  OracleAIClient,
39	  buildStandardAdapters,
40	  getOracleRoute,
41	  resolveRouteFromSettings,
42	  getRecentMessages,
43	  getRelevantOpenGaps,
44	  makeBlock,
45	  searchWithRetrievalPlan,
46	  buildRetrievalPlanFromQuery,
47	  type OracleModelRoute,
48	  type OraclePromptPlan,
49	  type RetrievalPlanSearchScope,
50	} from '@oracle/ai';
51	import { getDirectDb } from '@oracle/db/client';
52	import {
53	  channels,
54	  channelParticipants,
55	  documents,
56	  employeeIdentities,
57	  employees,
58	  messageAttachments,
59	  messages,
60	  modelRunUsageDetails,
61	  modelRuns,
62	  oracleContextPacks,
63	  providerResponseSessions,
64	  settings,
65	  type OracleDb,
66	} from '@oracle/db';
67	import { getServerSupabase } from '@/lib/supabase/server';
68	
69	const BodySchema = z.object({
70	  channelId: z.uuid(),
71	  force: z.boolean().optional(),
72	});
73	
74	const FALLBACK_ROUTE_ID = 'anthropic_claude_haiku_4_5_interview_primary';
75	
76	// Minimum size for routing a chat-attached PDF through the Vertex GCS
77	// file-backed cache. Below this, Gemini's explicit-cache minimum-token floor
78	// makes caching unprofitable (and risky — see route logic), so we leave small
79	// files on the inline path.
80	const VERTEX_CHAT_FILE_CACHE_MIN_BYTES = 256 * 1024;
81	
82	// Lazy singleton OracleAIClient with direct provider adapters (R-providers).
83	// Anthropic / Vertex / OpenAI raw SDKs per DECISIONS.md D6 — no Vercel AI
84	// SDK, no OpenRouter in this path.
85	//
86	// The adapter constructors throw when their provider API key is missing, so
87	// we MUST defer instantiation until the first request. At Next.js build time,
88	// the "Collect page data" phase imports this module without the runtime env
89	// vars in scope — eagerly constructing the singleton there fails the build.
90	let _oracleClient: OracleAIClient | null = null;
91	function getOracleClient(): OracleAIClient {
92	  if (!_oracleClient) {
93	    _oracleClient = new OracleAIClient({
94	      adapters: buildStandardAdapters(),
95	      fallbackOnError: true,
96	    });
97	  }
98	  return _oracleClient;
99	}
100	
101	export async function POST(req: NextRequest) {
102	  let body: z.infer<typeof BodySchema>;
103	  try {
104	    body = BodySchema.parse(await req.json());
105	  } catch (err) {
106	    return NextResponse.json({ error: 'bad_request', detail: String(err) }, { status: 400 });
107	  }
108	
109	  // ── 1. Auth ──────────────────────────────────────────────────────────
110	  const supabase = await getServerSupabase();
111	  const { data: userData } = await supabase.auth.getUser();
112	  if (!userData.user) {
113	    return NextResponse.json({ error: 'unauthenticated' }, { status: 401 });
114	  }
115	
116	  const db = getDirectDb();
117	  const meRows = await db
118	    .select({ employee: employees })
119	    .from(employees)
120	    .innerJoin(employeeIdentities, eq(employeeIdentities.employeeId, employees.id))
121	    .where(eq(employeeIdentities.authUserId, userData.user.id))
122	    .limit(1);
123	  const me = meRows[0]?.employee;
124	  if (!me || me.disabledAt) {
125	    return NextResponse.json({ error: 'not_approved' }, { status: 403 });
126	  }
127	
128	  // ── 2. Channel membership + group-chat detection ─────────────────────
129	  const [membership, channelRows] = await Promise.all([
130	    db
131	      .select()
132	      .from(channelParticipants)
133	      .where(
134	        and(
135	          eq(channelParticipants.channelId, body.channelId),
136	          eq(channelParticipants.employeeId, me.id),
137	        ),
138	      )
139	      .limit(1),
140	    db
141	      .select({ isGroupChat: channels.isGroupChat })
142	      .from(channels)
143	      .where(eq(channels.id, body.channelId))
144	      .limit(1),
145	  ]);
146	  if (membership.length === 0) {
147	    return NextResponse.json({ error: 'not_in_channel' }, { status: 403 });
148	  }
149	  const isGroupChat = channelRows[0]?.isGroupChat ?? false;
150	
151	  // ── 3. Retrieval bundle ──────────────────────────────────────────────
152	  const recent = await getRecentMessages(db, body.channelId);
153	  if (recent.length === 0) {
154	    return NextResponse.json(
155	      { error: 'no_user_message', detail: 'Channel has no messages.' },
156	      { status: 400 },
157	    );
158	  }
159	
160	  // Direct-mention gate (group chats only; DM is always direct).
161	  const latestUserMessage = [...recent].reverse().find((m) => m.role === 'user');
162	  if (!latestUserMessage) {
163	    return NextResponse.json({ ok: true, skipped: 'no_user_message' });
164	  }
165	  if (!body.force && isGroupChat) {
166	    if (!/^\s*(@oracle\b|oracle,)/i.test(latestUserMessage.content)) {
167	      return NextResponse.json({ ok: true, skipped: 'no_direct_mention' });
168	    }
169	  }
170	
171	  const openGaps = await getRelevantOpenGaps(db, me);
172	  // Build a RetrievalPlan from the latest message — applies domain-hint inference,
173	  // entity-type exclusions, and document-class exclusions before vector search
174	  // (spec docs/oracle/07-knowledge-segmentation.md "Retrieval rule").
175	  const queryForClaims = latestUserMessage.content;
176	  // Use the employee's departments as a soft RRF bonus — not a filter.
177	  // Falls back to legacy single `department` field if `departments` is empty.
178	  const deptHints =
179	    me.departments.length > 0
180	      ? me.departments
181	      : me.department ? [me.department] : [];
182	  const retrievalPlan = buildRetrievalPlanFromQuery(queryForClaims, {
183	    topK: 8,
184	    departmentHints: deptHints,
185	  });
186	  // Reader locale ('zh-CN' for the manually-routed China group, else 'en').
187	  // Drives claim/Brain rendering language and the answer-language instruction.
188	  const locale = coerceLocale(me.locale);
189	  const relevantClaims = queryForClaims
190	    ? await searchWithRetrievalPlan(db, retrievalPlan, locale)
191	    : [];
192	
193	  // ── 4. Resolve curated interview route ───────────────────────────────
194	  const route = await resolveInterviewRoute(db);
195	  const visionCapable = isVisionCapableRoute(route);
196	
197	  // ── 5. Compile prompt blocks (stable system + dynamic context) ───────
198	  const contextLines: string[] = [];
199	  contextLines.push(`---\nCONTEXT FOR THIS TURN:`);
200	  // Bilingual (china_imp.md): instruct the model to converse in the reader's
201	  // language. Claims/Brain context above is already rendered in this locale.
202	  if (locale === 'zh-CN') {
203	    contextLines.push(
204	      `Respond to this employee entirely in Simplified Chinese (简体中文). ` +
205	        `Write your questions, explanations, and summaries in Chinese.`,
206	    );
207	  }
208	  const deptDisplay = me.departments.length > 0
209	    ? me.departments.join(', ')
210	    : (me.department ?? 'Unknown');
211	  contextLines.push(`You are speaking with ${me.name} (${me.role}, ${deptDisplay}).`);
212	  if (openGaps.length > 0) {
213	    contextLines.push(`\nOpen gaps you may weave in if relevant:`);
214	    for (const g of openGaps) {
215	      contextLines.push(`- [${g.priority}] ${g.questionToAsk}`);
216	    }
217	  }
218	  if (relevantClaims.length > 0) {
219	    contextLines.push(`\nApproved claims that may be relevant:`);
220	    for (const c of relevantClaims) {
221	      contextLines.push(`- ${c.summary} (impact ${c.impactScore})`);
222	    }
223	  }
224	  const dynamicContext = contextLines.join('\n');
225	
226	  const blocks = [
227	    makeBlock({
228	      id: 'oracle-system',
229	      label: 'Oracle interview system prompt',
230	      kind: 'stable_system',
231	      content: ORACLE_SYSTEM_PROMPT,
232	      reasonIncluded: 'oracle prompt v' + ORACLE_SYSTEM_PROMPT_VERSION,
233	    }),
234	    makeBlock({
235	      id: 'turn-context',
236	      label: 'Per-turn retrieval bundle (employee + gaps + relevant claims)',
237	      kind: 'retrieved_context',
238	      content: dynamicContext,
239	      reasonIncluded: `gaps=${openGaps.length}, claims=${relevantClaims.length}`,
240	    }),
241	  ];
242	
243	  const plan = getOracleClient().compile({
244	    taskType: 'interview_chat',
245	    routeId: route.routeId,
246	    promptVersion: ORACLE_SYSTEM_PROMPT_VERSION,
247	    blocks,
248	    observability: {
249	      includedMessageIds: recent.map((m) => m.id),
250	      includedGapIds: openGaps.map((g) => g.id),
251	      includedClaimIds: relevantClaims.map((c) => c.id),
252	      // Retrieval scope audit — stored in oracle_context_packs.selected_domains.
253	      // domain_filtered → actual domain IDs used for pre-filtering.
254	      // global_fallback → '_global_fallback' tag; query
255	      //   WHERE selected_domains @> ARRAY['_global_fallback'] to find heuristic gaps.
256	      // global_explicit → '_global_explicit' tag (intentional wide search).
257	      selectedDomains: scopeTag(retrievalPlan.topDomainHints, retrievalPlan.searchScope),
258	    },
259	  });
260	
261	  // ── 6. Stage context pack BEFORE the model call ──────────────────────
262	  const [contextPack] = await db
263	    .insert(oracleContextPacks)
264	    .values(buildContextPackInsert(plan))
265	    .returning({ id: oracleContextPacks.id });
266	  if (!contextPack) {
267	    return NextResponse.json({ error: 'context_pack_failed' }, { status: 500 });
268	  }
269	
270	  // ── 7. Build multi-turn conversation (with attachments for vision routes) ─
271	  const recentIds = recent.map((m) => m.id);
272	  const attachmentRows =
273	    visionCapable && recentIds.length > 0
274	      ? await db
275	          .select({
276	            messageId: messageAttachments.messageId,
277	            storageBucket: documents.storageBucket,
278	            storagePath: documents.storagePath,
279	            fileType: documents.fileType,
280	            fileName: documents.fileName,
281	          })
282	          .from(messageAttachments)
283	          .innerJoin(documents, eq(documents.id, messageAttachments.documentId))
284	          .where(inArray(messageAttachments.messageId, recentIds))
285	      : [];
286	
287	  type AttRow = (typeof attachmentRows)[number];
288	  const attachmentMap = new Map<string, AttRow[]>();
289	  for (const att of attachmentRows) {
290	    const list = attachmentMap.get(att.messageId) ?? [];
291	    list.push(att);
292	    attachmentMap.set(att.messageId, list);
293	  }
294	
295	  const serviceSupabase = createServiceRoleClient();
296	
297	  // ── 7a. Vertex GCS file-backed cache for a large attached PDF ────────
298	  // When the interview route runs on Vertex AND a GCS cache bucket is
299	  // configured, cache the most-recent large PDF in the thread as a Gemini
300	  // cachedContent prefix (gs:// fileData) instead of re-sending it as base64
301	  // on every turn. The conversation turns ride on top of the cache as live
302	  // text contents (the adapter preserves multi-turn history on the file-cache
303	  // path). When this activates we EXCLUDE inline attachment parts so the doc
304	  // is not double-sent; v1 limitation: only this single cached document is
305	  // provided to the model, other attachments are not separately inlined.
306	  //
307	  // Gated on the bucket env: without it the adapter no-ops the file path, so
308	  // excluding the inline copy would leave the model with no document at all.
309	  const fileCacheEnabled =
310	    route.provider === 'vertex' && !!process.env.GOOGLE_VERTEX_CONTEXT_CACHE_GCS_BUCKET;
311	  let vertexFileCacheSource:
312	    | { localPath: string; mimeType: string; fileName: string; sourceHash: string }
313	    | undefined;
314	  let cachedTempPath: string | undefined;
315	  if (fileCacheEnabled) {
316	    const candidate = pickCacheablePdf(recent, attachmentMap);
317	    if (candidate) {
318	      try {
319	        const { data: blob, error } = await serviceSupabase.storage
320	          .from(candidate.storageBucket)
321	          .download(candidate.storagePath);
322	        if (error || !blob) {
323	          console.warn('[chat] file-cache candidate download failed', candidate.storagePath, error?.message);
324	        } else {
325	          const buf = Buffer.from(await blob.arrayBuffer());
326	          if (buf.length >= VERTEX_CHAT_FILE_CACHE_MIN_BYTES) {
327	            cachedTempPath = await materializeVertexCacheTempFile(buf, candidate.fileName);
328	            vertexFileCacheSource = {
329	              localPath: cachedTempPath,
330	              mimeType: candidate.fileType,
331	              fileName: candidate.fileName,
332	              // `documents` has no content hash column — hash the bytes so the
333	              // cache key + GCS object name are stable across turns (enables reuse).
334	              sourceHash: createHash('sha256').update(buf).digest('hex'),
335	            };
336	          }
337	        }
338	      } catch (err) {
339	        console.warn('[chat] file-cache candidate preparation failed', candidate.storagePath, err);
340	      }
341	    }
342	  }
343	  // Only exclude inline attachment parts once we are certain the file cache
344	  // will carry the document; otherwise keep the existing inline behavior.
345	  const excludeInlineAttachments = !!vertexFileCacheSource;
346	
347	  type ChatContentPart =
348	    | { type: 'text'; text: string }
349	    | { type: 'image'; image: string }
350	    | { type: 'file'; data: string; mimeType: string };
351	  type ConversationMessage = {
352	    role: 'user' | 'assistant';
353	    content: string | ChatContentPart[];
354	  };
355	
356	  const conversationMessages: ConversationMessage[] = await Promise.all(
357	    recent
358	      .filter((m) => m.role !== 'system')
359	      .map(async (m) => {
360	        const role = m.role === 'assistant' ? ('assistant' as const) : ('user' as const);
361	        const textContent =
362	          m.role === 'user' && m.authorName ? `[${m.authorName}] ${m.content}` : m.content;
363	        const atts = attachmentMap.get(m.id) ?? [];
364	        if (atts.length === 0 || excludeInlineAttachments) return { role, content: textContent };
365	
366	        const parts: ChatContentPart[] = [{ type: 'text', text: textContent }];
367	        for (const att of atts) {
368	          try {
369	            const { data: blob, error } = await serviceSupabase.storage
370	              .from(att.storageBucket)
371	              .download(att.storagePath);
372	            if (error || !blob) {
373	              console.warn('[chat] could not download attachment', att.storagePath, error?.message);
374	              continue;
375	            }
376	            const buf = Buffer.from(await blob.arrayBuffer());
377	            const b64 = buf.toString('base64');
378	            if (att.fileType.startsWith('image/')) {
379	              parts.push({ type: 'image', image: `data:${att.fileType};base64,${b64}` });
380	            } else if (att.fileType === 'application/pdf') {
381	              parts.push({ type: 'file', data: b64, mimeType: 'application/pdf' });
382	            } else if (att.fileType.startsWith('text/')) {
383	              const text = buf.toString('utf8');
384	              parts.push({ type: 'text', text: `\n\n[File: ${att.fileName}]\n${text}\n[/File]` });
385	            }
386	          } catch (err) {
387	            console.error('[chat] attachment fetch failed', att.storagePath, err);
388	          }
389	        }
390	        return { role, content: parts.length === 1 ? textContent : parts };
391	      }),
392	  );
393	
394	  const safeMessages: ConversationMessage[] = visionCapable
395	    ? conversationMessages
396	    : conversationMessages.map((m) => {
397	        if (!Array.isArray(m.content)) return m;
398	        const textOnly = m.content
399	          .filter((p): p is { type: 'text'; text: string } => p.type === 'text')
400	          .map((p) => p.text)
401	          .join('\n');
402	        return { ...m, content: textOnly };
403	      });
404	
405	  // ── 8. Dispatch through OracleAIClient ───────────────────────────────
406	  const startedAt = Date.now();
407	  const qwenSessionKey = route.provider === 'qwen' ? `interview-chat:${body.channelId}` : null;
408	  const previousQwenSession =
409	    qwenSessionKey
410	      ? await db
411	          .select({
412	            latestResponseId: providerResponseSessions.latestResponseId,
413	            modelId: providerResponseSessions.modelId,
414	          })
415	          .from(providerResponseSessions)
416	          .where(
417	            and(
418	              eq(providerResponseSessions.provider, 'qwen'),
419	              eq(providerResponseSessions.sessionKey, qwenSessionKey),
420	            ),
421	          )
422	          .orderBy(desc(providerResponseSessions.updatedAt))
423	          .limit(1)
424	      : [];
425	  let oracleText = '';
426	  let inputTokens: number | undefined;
427	  let outputTokens: number | undefined;
428	  let cachedInputTokens: number | undefined;
429	  let modelError: string | undefined;
430	  let success = false;
431	  let usageRaw: unknown = null;
432	  let providerRequestId: string | undefined;
433	  let actualRouteId = route.routeId;
434	  let actualProvider = route.provider;
435	  let actualModelId = route.modelId;
436	  let fellBackFromRouteId: string | undefined;
437	  let fallbackReason: string | undefined;
438	
439	  try {
440	    // Cache-friendly ordering: fold the volatile per-turn runtime context
441	    // (gaps + freshly-retrieved claims, which change every turn) into the LAST
442	    // user turn so the system prompt + prior conversation history stay a stable,
443	    // cacheable prefix. Prepending it (the old behavior) changed message index 1
444	    // on every turn and busted provider prefix caching for the whole thread.
445	    const runtimeBlock =
446	      '[Oracle runtime context - not part of the employee chat transcript]\n' +
447	      dynamicContext;
448	    const messagesWithContext: ConversationMessage[] = safeMessages.map((m) => ({ ...m }));
449	    const lastTurn = messagesWithContext[messagesWithContext.length - 1];
450	    if (!lastTurn || lastTurn.role !== 'user') {
451	      messagesWithContext.push({ role: 'user', content: runtimeBlock });
452	    } else if (typeof lastTurn.content === 'string') {
453	      lastTurn.content = `${lastTurn.content}\n\n${runtimeBlock}`;
454	    } else {
455	      lastTurn.content = [...lastTurn.content, { type: 'text', text: runtimeBlock }];
456	    }
457	    const result = await getOracleClient().runText({
458	      taskType: 'interview_chat',
459	      routeId: route.routeId,
460	      promptVersion: ORACLE_SYSTEM_PROMPT_VERSION,
461	      blocks,
462	      observability: {
463	        includedMessageIds: recent.map((m) => m.id),
464	        includedGapIds: openGaps.map((g) => g.id),
465	        includedClaimIds: relevantClaims.map((c) => c.id),
466	      },
467	      providerOptions: {
468	        messages: messagesWithContext,
469	        temperature: 0.4,
470	        cache: {
471	          preferLongLivedCache: true,
472	          // 30 min when caching an attached document for an active chat;
473	          // otherwise the default short interview-context TTL.
474	          cacheTtlSeconds: vertexFileCacheSource ? 30 * 60 : 10 * 60,
475	          expectedReuseCount: 6,
476	          // Activates the adapter's explicit file-cache path (Vertex only).
477	          preferExplicitCache: !!vertexFileCacheSource,
478	          persistProviderCacheRecord: route.provider === 'vertex',
479	          sourceDescription: `channel ${body.channelId} interview context`,
480	          cleanupOwner: 'chat-route',
481	          latestPlannedReuseStep: 'interview_chat',
482	          vertexFileCacheSource,
483	          sessionCacheKey:
484	            qwenSessionKey ?? undefined,
485	          previousResponseId:
486	            route.provider === 'qwen'
487	              ? previousQwenSession[0]?.modelId === route.modelId
488	                ? previousQwenSession[0]?.latestResponseId
489	                : undefined
490	              : undefined,
491	        },
492	      },
493	    });
494	    oracleText = result.text;
495	    inputTokens = result.usage.inputTokens;
496	    outputTokens = result.usage.outputTokens;
497	    cachedInputTokens = result.usage.cachedInputTokens;
498	    usageRaw = result.usage.rawUsageJson;
499	    providerRequestId = result.usage.providerRequestId;
500	    actualRouteId = result.routeId ?? route.routeId;
501	    actualProvider = (result.provider as typeof route.provider | undefined) ?? route.provider;
502	    actualModelId = result.modelId ?? route.modelId;
503	    fellBackFromRouteId = result.fellBackFromRouteId;
504	    fallbackReason = result.fallbackReason;
505	    success = true;
506	  } catch (err) {
507	    modelError = err instanceof Error ? err.message : String(err);
508	    console.error('[chat] model error', err);
509	  } finally {
510	    // The GCS object is reaped by the adapter's cache-TTL sweeper; we only own
511	    // the local temp file. Best-effort cleanup.
512	    if (cachedTempPath) {
513	      await unlink(cachedTempPath).catch(() => undefined);
514	    }
515	  }
516	
517	  // ── 9. Log model_runs + model_run_usage_details + back-link pack ───
518	  const [modelRun] = await db
519	    .insert(modelRuns)
520	    .values({
521	      taskType: 'interview_chat',
522	      model: actualModelId,
523	      provider: actualProvider,
524	      promptVersion: ORACLE_SYSTEM_PROMPT_VERSION,
525	      inputHash: plan.metadata.stablePrefixHash,
526	      inputTokens: inputTokens ?? null,
527	      outputTokens: outputTokens ?? null,
528	      latencyMs: Date.now() - startedAt,
529	      success,
530	      error: modelError ?? null,
531	    })
532	    .returning({ id: modelRuns.id });
533	
534	  if (modelRun) {
535	    await db.insert(modelRunUsageDetails).values({
536	      modelRunId: modelRun.id,
537	      contextPackId: contextPack.id,
538	      routeId: actualRouteId,
539	      inputTokens: inputTokens ?? null,
540	      cachedInputTokens: cachedInputTokens ?? null,
541	      outputTokens: outputTokens ?? null,
542	      providerRequestId: providerRequestId ?? null,
543	      rawUsageJson: usageRaw ?? null,
544	      fellBackFromRouteId: fellBackFromRouteId ?? null,
545	      fallbackReason: fallbackReason ?? null,
546	    });
547	    await db
548	      .update(oracleContextPacks)
549	      .set({ modelRunId: modelRun.id })
550	      .where(eq(oracleContextPacks.id, contextPack.id));
551	
552	    if (actualProvider === 'qwen' && providerRequestId && qwenSessionKey) {
553	      await db
554	        .insert(providerResponseSessions)
555	        .values({
556	          provider: 'qwen',
557	          sessionKey: qwenSessionKey,
558	          scopeKind: 'channel',
559	          scopeId: body.channelId,
560	          modelId: actualModelId,
561	          latestResponseId: providerRequestId,
562	          lastContextPackId: contextPack.id,
563	          lastModelRunId: modelRun.id,
564	          metadataJson: {
565	            routeId: actualRouteId,
566	          },
567	        })
568	        .onConflictDoUpdate({
569	          target: [
570	            providerResponseSessions.provider,
571	            providerResponseSessions.sessionKey,
572	          ],
573	          set: {
574	            modelId: actualModelId,
575	            latestResponseId: providerRequestId,
576	            lastContextPackId: contextPack.id,
577	            lastModelRunId: modelRun.id,
578	            metadataJson: {
579	              routeId: actualRouteId,
580	            },
581	            updatedAt: new Date(),
582	          },
583	        });
584	    }
585	  }
586	
587	  if (!success || !oracleText.trim()) {
588	    return NextResponse.json(
589	      { error: 'model_failed', detail: modelError ?? 'empty response' },
590	      { status: 502 },
591	    );
592	  }
593	
594	  // ── 10. Persist Oracle reply as assistant message ───────────────────
595	  const [inserted] = await db
596	    .insert(messages)
597	    .values({
598	      channelId: body.channelId,
599	      employeeId: null,
600	      role: 'assistant',
601	      content: oracleText.trim(),
602	      extractionStatus: 'skipped',
603	    })
604	    .returning();
605	
606	  return NextResponse.json({
607	    ok: true,
608	    messageId: inserted?.id,
609	    routeId: actualRouteId,
610	    model: actualModelId,
611	    provider: actualProvider,
612	    contextPackId: contextPack.id,
613	    modelRunId: modelRun?.id ?? null,
614	    latencyMs: Date.now() - startedAt,
615	  });
616	}
