618	// ─────────────────────────────────────────────────────────────────────────
619	// Helpers
620	// ─────────────────────────────────────────────────────────────────────────
621	
622	/**
623	 * Build the selectedDomains array for the context pack.
624	 * - domain_filtered: return the actual domain IDs.
625	 * - global_fallback / global_explicit: return a single sentinel tag so
626	 *   operators can query: WHERE selected_domains @> ARRAY['_global_fallback'].
627	 */
628	function scopeTag(topDomainHints: string[], scope: RetrievalPlanSearchScope): string[] {
629	  if (topDomainHints.length > 0) return topDomainHints;
630	  return [`_${scope}`]; // '_global_fallback' or '_global_explicit'
631	}
632	
633	async function resolveInterviewRoute(db: OracleDb): Promise<OracleModelRoute> {
634	  // resolveRouteFromSettings handles catalog routeIds, OpenRouter "provider/model"
635	  // IDs from the pool picker, AND attaches the admin's saved reasoning effort.
636	  const resolved = await resolveRouteFromSettings(db, 'interview');
637	  if (resolved) return resolved;
638	  const fb = getOracleRoute(FALLBACK_ROUTE_ID);
639	  if (!fb) {
640	    throw new Error(
641	      `[chat] default_interview_route unset/unresolvable and fallback "${FALLBACK_ROUTE_ID}" missing.`,
642	    );
643	  }
644	  console.warn(`[chat] default_interview_route unset/unresolvable; using fallback "${FALLBACK_ROUTE_ID}".`);
645	  return fb;
646	}
647	
648	/**
649	 * Pick at most ONE document to route through the Vertex GCS file cache: the
650	 * most-recent PDF attachment in the recent-message window. Walks newest→oldest
651	 * so an attachment on the latest turn wins.
652	 */
653	function pickCacheablePdf<T extends { fileType: string }>(
654	  recentMessages: Array<{ id: string }>,
655	  attachmentMap: Map<string, T[]>,
656	): T | null {
657	  for (let i = recentMessages.length - 1; i >= 0; i -= 1) {
658	    const atts = attachmentMap.get(recentMessages[i]!.id) ?? [];
659	    const pdf = atts.find((a) => a.fileType === 'application/pdf');
660	    if (pdf) return pdf;
661	  }
662	  return null;
663	}
664	
665	async function materializeVertexCacheTempFile(buffer: Buffer, fileName: string): Promise<string> {
666	  const safeName = fileName.replace(/[^a-zA-Z0-9._-]/g, '_');
667	  const tempPath = join(tmpdir(), `oracle-chat-vertex-cache-${Date.now()}-${safeName}`);
668	  await writeFile(tempPath, buffer);
669	  return tempPath;
670	}
671	
672	function isVisionCapableRoute(route: OracleModelRoute): boolean {
673	  // Vision detection from the route's flags + a name regex fallback. The
674	  // curated catalog already encodes supportsVision on each route; the
675	  // regex is a defensive belt-and-suspenders in case a catalog entry
676	  // gets misconfigured.
677	  if (route.supportsVision) return true;
678	  return /claude|gpt-4o|gemini|llava|pixtral|qwen.*vl|minicpm/i.test(route.modelId);
679	}
