681	function buildContextPackInsert(plan: OraclePromptPlan) {
682	  return {
683	    taskType: plan.taskType,
684	    routeId: plan.routeId,
685	    promptVersion: plan.promptVersion,
686	    schemaVersion: plan.schemaVersion ?? null,
687	    stablePrefixHash: plan.metadata.stablePrefixHash,
688	    semiStableContextHash: plan.metadata.semiStableContextHash ?? null,
689	    retrievedContextHash: plan.metadata.retrievedContextHash ?? null,
690	    dynamicInputHash: plan.metadata.dynamicInputHash,
691	    toolSchemaHash: plan.metadata.toolSchemaHash ?? null,
692	    outputSchemaHash: plan.metadata.outputSchemaHash ?? null,
693	    blocksJson: plan.blocks.map((b) => ({
694	      id: b.id,
695	      label: b.label,
696	      kind: b.kind,
697	      hash: b.hash,
698	      tokenEstimate: b.tokenEstimate ?? null,
699	      cacheEligible: b.cacheEligible,
700	      reasonIncluded: b.reasonIncluded,
701	    })),
702	    retrievalPlanId: plan.metadata.retrievalPlanId ?? null,
703	    selectedDomains: plan.metadata.selectedDomains ?? null,
704	    selectedSourceTypes: plan.metadata.selectedSourceTypes ?? null,
705	    selectedProcessStages: plan.metadata.selectedProcessStages ?? null,
706	    selectedEntityIds: plan.metadata.selectedEntityIds ?? null,
707	    includedMessageIds: plan.metadata.includedMessageIds ?? null,
708	    includedDocumentChunkIds: plan.metadata.includedDocumentChunkIds ?? null,
709	    includedClaimIds: plan.metadata.includedClaimIds ?? null,
710	    includedGapIds: plan.metadata.includedGapIds ?? null,
711	    includedContradictionIds: plan.metadata.includedContradictionIds ?? null,
712	  };
713	}
