1	// Oracle remote MCP server.
2	//
3	// Exposes the Oracle's approved business knowledge to external AI agents over
4	// the Model Context Protocol (Streamable HTTP transport). Endpoint:
5	//
6	//   POST https://oracle.designflow.app/api/mcp/mcp
7	//
8	// Auth: a single static bearer token in `ORACLE_MCP_TOKEN`. Every request must
9	// send `Authorization: Bearer <token>`. This is a machine-to-machine endpoint
10	// for trusted agents building software for us — it is NOT tied to a Supabase
11	// user session. Rotate the token by changing the env var.
12	//
13	// Transport: Streamable HTTP, stateless (no Redis). SSE is disabled — the
14	// current MCP spec (2025-03-26+) uses Streamable HTTP, which every modern
15	// client speaks. The `[transport]` route segment is required by mcp-handler;
16	// with basePath '/api/mcp' the live endpoint is '/api/mcp/mcp'.
17	//
18	// tools/list is intentionally tiny: it exposes only the five always-on tools
19	// (health, list_capabilities, tool_search, get_capability_details, invoke_tool).
20	// Real operations live in a hidden registry (apps/web/lib/mcp/capabilities.ts)
21	// reached via invoke_tool. They are read-only and route through the same
22	// retrieval path as employee chat, so they cannot surface unapproved knowledge.
23	// See apps/web/lib/mcp/README.md.
24	
25	import { timingSafeEqual } from 'node:crypto';
26	import { createMcpHandler, withMcpAuth } from 'mcp-handler';
27	import type { AuthInfo } from '@modelcontextprotocol/sdk/server/auth/types.js';
28	import { getDirectDb } from '@oracle/db/client';
29	import { registerOracleMcpTools } from '@/lib/mcp/server-tools';
30	
31	// Drizzle/postgres need the Node runtime; retrieval is dynamic per request.
32	export const runtime = 'nodejs';
33	export const dynamic = 'force-dynamic';
34	export const maxDuration = 60;
35	
36	const baseHandler = createMcpHandler(
37	  (server) => {
38	    registerOracleMcpTools(server, { db: getDirectDb() });
39	  },
40	  {
41	    serverInfo: { name: 'oracle-knowledge', version: '1.0.0' },
42	  },
43	  {
44	    basePath: '/api/mcp',
45	    disableSse: true,
46	    maxDuration: 60,
47	    verboseLogs: process.env.NODE_ENV !== 'production',
48	  },
49	);
50	
51	/** Constant-time bearer-token check against ORACLE_MCP_TOKEN. */
52	function verifyToken(_req: Request, bearerToken?: string): AuthInfo | undefined {
53	  const expected = process.env.ORACLE_MCP_TOKEN;
54	  if (!expected) {
55	    // Misconfiguration: never accept requests when no token is set.
56	    console.error('[mcp] ORACLE_MCP_TOKEN is not set — rejecting all MCP requests.');
57	    return undefined;
58	  }
59	  if (!bearerToken) return undefined;
60	
61	  const a = Buffer.from(bearerToken);
62	  const b = Buffer.from(expected);
63	  if (a.length !== b.length || !timingSafeEqual(a, b)) return undefined;
64	
65	  return {
66	    token: bearerToken,
67	    clientId: 'oracle-mcp-client',
68	    scopes: [],
69	  };
70	}
71	
72	const handler = withMcpAuth(baseHandler, verifyToken, { required: true });
73	
74	export { handler as GET, handler as POST, handler as DELETE };
