1	// POST /api/messages — server-side message insert.
2	//
3	// Writes go through this route instead of the browser Supabase client so that:
4	//   * The insert uses the service-role connection (DIRECT_URL) which bypasses
5	//     the browser-client auth / RLS layer entirely.
6	//   * requireEmployee() validates the session server-side — the same path that
7	//     already works for every other server component.
8	//
9	// The browser realtime subscription still handles delivery of the inserted row.
10	
11	import { NextResponse, type NextRequest } from 'next/server';
12	import { eq, and } from 'drizzle-orm';
13	import { z } from 'zod';
14	import { requireEmployee } from '@/lib/auth-guard';
15	import { getDirectDb } from '@oracle/db/client';
16	import { channels, channelParticipants, messages } from '@oracle/db/schema';
17	
18	export const dynamic = 'force-dynamic';
19	
20	const BodySchema = z.object({
21	  channelId: z.uuid(),
22	  content: z.string().min(1).max(10_000),
23	});
24	
25	export async function POST(request: NextRequest) {
26	  // 1. Authenticate — same guard used by every server component.
27	  let me;
28	  try {
29	    me = await requireEmployee();
30	  } catch {
31	    // requireEmployee redirects via next/navigation; if called from fetch()
32	    // it throws instead. Return a clean 401.
33	    return NextResponse.json({ error: 'Unauthenticated' }, { status: 401 });
34	  }
35	
36	  // 2. Parse + validate body.
37	  let body: { channelId: string; content: string };
38	  try {
39	    body = BodySchema.parse(await request.json());
40	  } catch {
41	    return NextResponse.json({ error: 'Invalid request body' }, { status: 400 });
42	  }
43	
44	  const db = getDirectDb();
45	
46	  // 3. Confirm the caller is a participant of this channel.
47	  const membership = await db
48	    .select()
49	    .from(channelParticipants)
50	    .where(
51	      and(
52	        eq(channelParticipants.channelId, body.channelId),
53	        eq(channelParticipants.employeeId, me.id),
54	      ),
55	    )
56	    .limit(1);
57	
58	  if (membership.length === 0) {
59	    return NextResponse.json({ error: 'Not a channel participant' }, { status: 403 });
60	  }
61	
62	  // 4. Confirm the channel is active.
63	  const channelRows = await db
64	    .select({ status: channels.status })
65	    .from(channels)
66	    .where(eq(channels.id, body.channelId))
67	    .limit(1);
68	
69	  if (!channelRows[0] || channelRows[0].status !== 'active') {
70	    return NextResponse.json({ error: 'Channel not found or not active' }, { status: 404 });
71	  }
72	
73	  // 5. Insert the message.
74	  const inserted = await db
75	    .insert(messages)
76	    .values({
77	      channelId: body.channelId,
78	      employeeId: me.id,
79	      role: 'user',
80	      content: body.content,
81	    })
82	    .returning();
83	
84	  const msg = inserted[0];
85	  if (!msg) {
86	    return NextResponse.json({ error: 'Insert failed' }, { status: 500 });
87	  }
88	
89	  return NextResponse.json(
90	    {
91	      id: msg.id,
92	      channelId: msg.channelId,
93	      employeeId: msg.employeeId,
94	      role: msg.role,
95	      content: msg.content,
96	      createdAt: msg.createdAt,
97	    },
98	    { status: 201 },
99	  );
100	}
