1	// POST /api/teams/bot/messages
2	//
3	// Microsoft Teams Bot Framework endpoint. This is the Teams-native entry point
4	// so users can add The Oracle app inside Teams and type:
5	//
6	//   @theoracle join <Teams meeting link>
7	//
8	// In meeting scope, TeamsInfo.getMeetingInfo() may provide the join URL, so a
9	// plain "join" can work there. If Teams does not provide it, we ask for the
10	// link. The actual live listener is still Recall.ai; this bot is the Teams UX
11	// wrapper that summons Recall into the meeting.
12	
13	import { NextResponse, type NextRequest } from 'next/server';
14	import {
15	  ActivityTypes,
16	  CloudAdapter,
17	  ConfigurationBotFrameworkAuthentication,
18	  TeamsInfo,
19	  TurnContext,
20	  type Activity,
21	} from 'botbuilder';
22	import { createRecallLiveBot, type RecallSttProvider } from '@/lib/recall';
23	
24	export const dynamic = 'force-dynamic';
25	export const runtime = 'nodejs';
26	
27	let adapterSingleton: CloudAdapter | null = null;
28	
29	function getAdapter(): CloudAdapter {
30	  const appId = process.env.MICROSOFT_BOT_APP_ID;
31	  const appPassword = process.env.MICROSOFT_BOT_APP_PASSWORD;
32	  const appTenantId = process.env.MICROSOFT_BOT_TENANT_ID;
33	  if (!appId || !appPassword) {
34	    throw new Error('MICROSOFT_BOT_APP_ID / MICROSOFT_BOT_APP_PASSWORD are not configured');
35	  }
36	  if (!adapterSingleton) {
37	    adapterSingleton = new CloudAdapter(
38	      new ConfigurationBotFrameworkAuthentication({
39	        MicrosoftAppId: appId,
40	        MicrosoftAppPassword: appPassword,
41	        MicrosoftAppType: appTenantId ? 'SingleTenant' : 'MultiTenant',
42	        MicrosoftAppTenantId: appTenantId,
43	      }),
44	    );
45	  }
46	  return adapterSingleton;
47	}
48	
49	function removeBotMention(context: TurnContext): string {
50	  const activity = context.activity;
51	  const botId = activity.recipient?.id;
52	  let text = activity.text ?? '';
53	  for (const entity of activity.entities ?? []) {
54	    if (entity.type !== 'mention') continue;
55	    const mentioned = entity.mentioned as { id?: string } | undefined;
56	    if (mentioned?.id && mentioned.id === botId) {
57	      text = text.replace(entity.text ?? '', '');
58	    }
59	  }
60	  return text.replace(/\s+/g, ' ').trim();
61	}
62	
63	function extractTeamsUrl(text: string): string | null {
64	  const m = text.match(/https:\/\/teams\.microsoft\.com\/[^\s<>"']+/i);
65	  return m?.[0] ?? null;
66	}
67	
68	function extractProvider(text: string): RecallSttProvider {
69	  if (/\bassembly\b|\bassemblyai\b/i.test(text)) return 'assembly_ai_v3_streaming';
70	  return 'elevenlabs_streaming';
71	}
72	
73	function isJoinCommand(text: string): boolean {
74	  return /^(join|listen|start|bring oracle in)\b/i.test(text) || extractTeamsUrl(text) !== null;
75	}
76	
77	async function meetingJoinUrlFromContext(context: TurnContext): Promise<string | null> {
78	  const channelData = context.activity.channelData as { meeting?: { id?: string } } | undefined;
79	  const meetingId = channelData?.meeting?.id;
80	  if (!meetingId) return null;
81	  try {
82	    const info = await TeamsInfo.getMeetingInfo(context, meetingId);
83	    return info.details?.joinUrl ?? null;
84	  } catch (err) {
85	    console.warn('[teams/bot] could not load meeting info', err);
86	    return null;
87	  }
88	}
89	
90	async function handleTurn(context: TurnContext, req: NextRequest): Promise<void> {
91	  if (context.activity.type !== ActivityTypes.Message) {
92	    if (context.activity.type === ActivityTypes.ConversationUpdate) {
93	      await context.sendActivity('theoracle is ready. In a meeting chat, type "join" or "join <Teams meeting link>".');
94	    }
95	    return;
96	  }
97	
98	  const commandText = removeBotMention(context);
99	  if (!isJoinCommand(commandText)) {
100	    await context.sendActivity('To bring Oracle into this meeting, type "join" or "join <Teams meeting link>".');
101	    return;
102	  }
103	
104	  const meetingUrl = extractTeamsUrl(commandText) ?? (await meetingJoinUrlFromContext(context));
105	  if (!meetingUrl) {
106	    await context.sendActivity('I can join, but I need the Teams meeting link. Type "join" followed by the meeting link.');
107	    return;
108	  }
109	
110	  const provider = extractProvider(commandText);
111	  const webhookUrl =
112	    process.env.RECALL_REALTIME_WEBHOOK_URL ??
113	    `${req.nextUrl.origin.replace(/\/+$/, '')}/api/teams/live/recall`;
114	
115	  try {
116	    await createRecallLiveBot({
117	      meetingUrl,
118	      webhookUrl,
119	      provider,
120	      botName: 'theoracle',
121	      metadata: {
122	        source: 'teams_bot_command',
123	        teams_conversation_id: context.activity.conversation?.id ?? '',
124	        teams_service_url: context.activity.serviceUrl ?? '',
125	      },
126	    });
127	    await context.sendActivity(
128	      'Oracle is joining now. If Teams shows a lobby prompt, admit it like any other meeting attendee.',
129	    );
130	  } catch (err) {
131	    await context.sendActivity(
132	      `I could not bring Oracle in yet: ${err instanceof Error ? err.message : String(err)}`,
133	    );
134	  }
135	}
136	
137	export async function POST(req: NextRequest): Promise<NextResponse> {
138	  let body: Activity;
139	  try {
140	    body = (await req.json()) as Activity;
141	  } catch {
142	    return NextResponse.json({ error: 'bad_json' }, { status: 400 });
143	  }
144	
145	  try {
146	    const adapter = getAdapter();
147	    await adapter.processActivityDirect(req.headers.get('authorization') ?? '', body, async (context) => {
148	      await handleTurn(context, req);
149	    });
150	    return new NextResponse(null, { status: 200 });
151	  } catch (err) {
152	    console.error('[teams/bot] turn failed', err);
153	    return NextResponse.json(
154	      { error: 'bot_turn_failed', detail: err instanceof Error ? err.message : String(err) },
155	      { status: 500 },
156	    );
157	  }
158	}
