1	// POST /api/teams/live/recall
2	//
3	// Recall.ai real-time transcript endpoint. Recall sends finalized
4	// `transcript.data` utterances here while the meeting is still in progress.
5	// Keep this handler fast: verify the signature, enqueue a worker task, return
6	// 202. The worker owns DB writes, LLM calls, and Teams chat replies.
7	
8	import { NextResponse, type NextRequest } from 'next/server';
9	import { triggerTask } from '@/lib/trigger';
10	import { verifyRecallRequest } from '@/lib/recall';
11	
12	export const dynamic = 'force-dynamic';
13	export const runtime = 'nodejs';
14	
15	export async function POST(req: NextRequest): Promise<NextResponse> {
16	  const raw = await req.text();
17	  const secret = process.env.RECALL_WEBHOOK_SECRET;
18	  if (!secret) {
19	    console.warn('[teams/live/recall] RECALL_WEBHOOK_SECRET missing');
20	    return NextResponse.json({ error: 'not_configured' }, { status: 503 });
21	  }
22	
23	  try {
24	    verifyRecallRequest({ secret, headers: req.headers, payload: raw });
25	  } catch (err) {
26	    console.warn('[teams/live/recall] signature verification failed', err);
27	    return NextResponse.json({ error: 'invalid_signature' }, { status: 400 });
28	  }
29	
30	  let body: unknown;
31	  try {
32	    body = JSON.parse(raw);
33	  } catch {
34	    return NextResponse.json({ error: 'bad_json' }, { status: 400 });
35	  }
36	
37	  void triggerTask('teams-live-recall-utterance', {
38	    receivedAt: new Date().toISOString(),
39	    event: body,
40	  });
41	
42	  return new NextResponse(null, { status: 202 });
43	}
44

1	// POST /api/teams/live/start
2	//
3	// Admin-only helper to send a Recall.ai bot into a live Teams meeting with
4	// real-time transcription enabled. This does not replace the Microsoft Graph
5	// post-call transcript pipeline; it adds live participation.
6	
7	import { NextResponse, type NextRequest } from 'next/server';
8	import { z } from 'zod';
9	import { requireAdmin } from '@/lib/auth-guard';
10	import { createRecallLiveBot, type RecallSttProvider } from '@/lib/recall';
11	
12	export const dynamic = 'force-dynamic';
13	export const runtime = 'nodejs';
14	
15	const BodySchema = z.object({
16	  meetingUrl: z.url(),
17	  provider: z.enum(['elevenlabs_streaming', 'assembly_ai_v3_streaming']).optional(),
18	  botName: z.string().min(1).max(100).optional(),
19	});
20	
21	export async function POST(req: NextRequest): Promise<NextResponse> {
22	  let admin;
23	  try {
24	    admin = await requireAdmin();
25	  } catch {
26	    return NextResponse.json({ error: 'unauthorized' }, { status: 401 });
27	  }
28	
29	  let body: z.infer<typeof BodySchema>;
30	  try {
31	    body = BodySchema.parse(await req.json());
32	  } catch (err) {
33	    return NextResponse.json({ error: 'bad_request', detail: String(err) }, { status: 400 });
34	  }
35	
36	  const webhookUrl =
37	    process.env.RECALL_REALTIME_WEBHOOK_URL ??
38	    `${req.nextUrl.origin.replace(/\/+$/, '')}/api/teams/live/recall`;
39	
40	  try {
41	    const bot = await createRecallLiveBot({
42	      meetingUrl: body.meetingUrl,
43	      webhookUrl,
44	      provider: body.provider as RecallSttProvider | undefined,
45	      botName: body.botName,
46	      metadata: {
47	        requested_by_employee_id: admin.id,
48	      },
49	    });
50	    return NextResponse.json({ ok: true, bot });
51	  } catch (err) {
52	    return NextResponse.json(
53	      { error: 'recall_create_failed', detail: err instanceof Error ? err.message : String(err) },
54	      { status: 502 },
55	    );
56	  }
57	}
