1	// POST/GET /api/teams/notifications
2	//
3	// The "always-on listener" for Microsoft Graph change notifications about
4	// Teams transcripts. Two standing subscriptions point here — ad-hoc calls
5	// (communications/adhocCalls/getAllTranscripts) and scheduled meetings
6	// (communications/onlineMeetings/getAllTranscripts). This handler is
7	// resource-agnostic: it decrypts whichever transcript fired and hands off to
8	// `teams-transcript-ingestion`, so no per-resource branching is needed.
9	//
10	// This endpoint MUST be deployed and publicly reachable BEFORE the subscription
11	// can be created — Graph validates it synchronously at subscription-create time
12	// by calling it with a ?validationToken=... that we have to echo back within
13	// 10 seconds. See apps/web/lib/microsoft-graph.ts createAdhocTranscriptSubscription.
14	//
15	// Responsibilities (kept deliberately fast — Graph disables subscriptions whose
16	// endpoint is slow or erroring):
17	//   1. Answer the validation handshake (echo validationToken as text/plain).
18	//   2. Verify the shared `clientState` secret on every real notification.
19	//   3. Decrypt the rich-notification payload to learn which transcript fired.
20	//   4. RECORD the meeting as available in `meeting_transcripts` (discovery only)
21	//      — it does NOT ingest. An admin picks meetings to ingest on
22	//      /admin/transcripts, which is what triggers teams-transcript-ingestion.
23	//   5. Handle lifecycle events by asking the subscription manager to reauthorize.
24	//
25	// Both notificationUrl and lifecycleNotificationUrl on the subscription point
26	// here; we branch on the payload shape.
27	
28	import { NextResponse, type NextRequest } from 'next/server';
29	import { sql } from 'drizzle-orm';
30	import { getDirectDb } from '@oracle/db/client';
31	import { triggerTask } from '@/lib/trigger';
32	import {
33	  decryptResourceData,
34	  type GraphEncryptedContent,
35	} from '@/lib/graph-notification-crypto';
36	
37	export const dynamic = 'force-dynamic';
38	export const runtime = 'nodejs'; // node:crypto + Buffer needed for decryption
39	
40	interface GraphNotification {
41	  subscriptionId?: string;
42	  clientState?: string;
43	  changeType?: string;
44	  resource?: string;
45	  resourceData?: { id?: string; '@odata.id'?: string } | null;
46	  encryptedContent?: GraphEncryptedContent;
47	  lifecycleEvent?: 'reauthorizationRequired' | 'subscriptionRemoved' | 'missed';
48	}
49	
50	interface GraphNotificationEnvelope {
51	  value?: GraphNotification[];
52	}
53	
54	/** Decrypted callTranscript shape — only the fields we use. */
55	interface DecryptedTranscript {
56	  transcriptContentUrl?: string;
57	  meetingId?: string;
58	  callId?: string;
59	  meetingOrganizer?: { user?: { id?: string; displayName?: string } } | null;
60	  createdDateTime?: string;
61	}
62	
63	/** Full Graph transcript id from the content URL (else the resource path). */
64	function deriveDiscoveryTranscriptId(
65	  contentUrl: string | null,
66	  resource: string | null,
67	): string | null {
68	  const src = contentUrl || resource || '';
69	  const m = src.match(/transcripts[('/]+([^')/]+)/i);
70	  return m && m[1] ? m[1] : null;
71	}
72	
73	/**
74	 * If this request is Graph's validation handshake, return the text/plain echo
75	 * response. Otherwise return null and let the caller process notifications.
76	 */
77	function handleValidation(req: NextRequest): NextResponse | null {
78	  const token = req.nextUrl.searchParams.get('validationToken');
79	  if (token === null) return null;
80	  return new NextResponse(token, {
81	    status: 200,
82	    headers: { 'content-type': 'text/plain' },
83	  });
84	}
85	
86	export function GET(req: NextRequest): NextResponse {
87	  return handleValidation(req) ?? NextResponse.json({ ok: true });
88	}
89	
90	export async function POST(req: NextRequest): Promise<NextResponse> {
91	  // 1. Validation handshake (fires on subscription create + renewal).
92	  const validation = handleValidation(req);
93	  if (validation) return validation;
94	
95	  // 2. Parse the envelope.
96	  let body: GraphNotificationEnvelope;
97	  try {
98	    body = (await req.json()) as GraphNotificationEnvelope;
99	  } catch {
100	    return NextResponse.json({ error: 'Bad JSON' }, { status: 400 });
101	  }
102	  const notifications = body.value ?? [];
103	
104	  const expectedClientState = process.env.TEAMS_WEBHOOK_CLIENT_STATE;
105	  const privateKeyPem = process.env.TEAMS_NOTIFICATION_PRIVATE_KEY;
106	
107	  for (const n of notifications) {
108	    // Lifecycle events (reauthorizationRequired / subscriptionRemoved / missed):
109	    // the subscription needs attention — let the manager handle it.
110	    if (n.lifecycleEvent) {
111	      void triggerTask('teams-subscription-manager', {
112	        reason: n.lifecycleEvent,
113	        subscriptionId: n.subscriptionId ?? null,
114	      });
115	      continue;
116	    }
117	
118	    // Reject anything that doesn't carry our shared secret.
119	    if (expectedClientState && n.clientState !== expectedClientState) {
120	      console.warn('[teams/notifications] clientState mismatch — ignoring');
121	      continue;
122	    }
123	
124	    // Decrypt to learn which transcript this is. We keep the unencrypted
125	    // `resource` path as a fallback so we can still identify it even if
126	    // decryption is unavailable (e.g. private key not yet configured).
127	    let transcriptContentUrl: string | null = null;
128	    let meetingId: string | null = null;
129	    let callId: string | null = null;
130	    let meetingTime: string | null = null;
131	    let organizerId: string | null = null;
132	    let organizerName: string | null = null;
133	    if (n.encryptedContent && privateKeyPem) {
134	      try {
135	        const resource = decryptResourceData(
136	          n.encryptedContent,
137	          privateKeyPem,
138	        ) as DecryptedTranscript;
139	        transcriptContentUrl = resource.transcriptContentUrl ?? null;
140	        meetingId = resource.meetingId ?? null;
141	        callId = resource.callId ?? null;
142	        meetingTime = resource.createdDateTime ?? null;
143	        organizerId = resource.meetingOrganizer?.user?.id ?? null;
144	        organizerName = resource.meetingOrganizer?.user?.displayName ?? null;
145	      } catch (err) {
146	        console.error('[teams/notifications] decrypt failed', err);
147	      }
148	    }
149	
150	    // DISCOVERY ONLY — record that this meeting's transcript is available; do
151	    // NOT ingest it. An admin chooses which meetings to ingest on
152	    // /admin/transcripts (which triggers teams-transcript-ingestion then).
153	    const transcriptId = deriveDiscoveryTranscriptId(transcriptContentUrl, n.resource ?? null);
154	    if (transcriptId) {
155	      try {
156	        await getDirectDb().execute(sql`
157	          INSERT INTO meeting_transcripts
158	            (transcript_id, meeting_id, call_id, organizer_id, organizer_name,
159	             transcript_content_url, meeting_time, status, discovered_via)
160	          VALUES
161	            (${transcriptId}, ${meetingId}, ${callId}, ${organizerId}, ${organizerName},
162	             ${transcriptContentUrl}, ${meetingTime}, 'available', 'subscription')
163	          ON CONFLICT (transcript_id) DO UPDATE SET
164	            meeting_id = COALESCE(EXCLUDED.meeting_id, meeting_transcripts.meeting_id),
165	            call_id = COALESCE(EXCLUDED.call_id, meeting_transcripts.call_id),
166	            organizer_id = COALESCE(EXCLUDED.organizer_id, meeting_transcripts.organizer_id),
167	            organizer_name = COALESCE(EXCLUDED.organizer_name, meeting_transcripts.organizer_name),
168	            transcript_content_url = COALESCE(EXCLUDED.transcript_content_url, meeting_transcripts.transcript_content_url),
169	            meeting_time = COALESCE(EXCLUDED.meeting_time, meeting_transcripts.meeting_time)
170	        `);
171	      } catch (err) {
172	        console.error('[teams/notifications] discovery upsert failed', err);
173	      }
174	    }
175	  }
176	
177	  // Always acknowledge quickly so Graph doesn't retry or disable the sub.
178	  return new NextResponse(null, { status: 202 });
179	}
